/* Variables disponibles: var(--accent)
   Clases: .dv-glass, .dv-label, .dv-safe-area
   Canvas: siempre 1920Г—1080 */

#master-container {
  font-family: 'Inter', -apple-system, sans-serif;
}

dvEngine.register({
  awake: (ctx) => {
    ctx.refs.block  = ctx.root.getElementById('title-block');
    ctx.refs.bar    = ctx.root.getElementById('accent-bar');
  },
  update: (ctx) => {
    const { refs, timeline, utils } = ctx;
    const { block, bar } = refs;
    if (!block || !bar) return;

    // в”Ђв”Ђв”Ђ ENTRADA в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    const ip = utils.clamp(timeline.introProgress, 0, 1);
    block.style.opacity   = ip.toString();
    block.style.transform = `translateY(${utils.lerp(30, 0, utils.easeOutCubic(ip))}px)`;

    const barP = utils.clamp((ip - 0.3) / 0.7, 0, 1);
    bar.style.width = `${utils.lerp(0, 300, utils.easeOutCubic(barP))}px`;

    // в”Ђв”Ђв”Ђ SALIDA в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    if (timeline.isOutro) {
      const op = utils.clamp(timeline.outroProgress, 0, 1);
      block.style.opacity = (1 - op).toString();
      bar.style.width     = `${utils.lerp(300, 0, utils.easeInOutCubic(op))}px`;
    }
  }
});
